+    let entry_count = u16::try_from(entries.len()).unwrap_or(u16::MAX);
+    listpack.extend_from_slice(&entry_count.to_le_bytes());
+    listpack.extend_from_slice(&encoded);
+    listpack.push(0xFF);
+    Some(listpack)
